import React from 'react';
import { Phone } from 'lucide-react'; // Package icon is no longer needed as we use an image

function Header() {
  return (
    <header className="bg-primary-dark text-white shadow-md">
      <div className="container mx-auto p-4 flex justify-between items-center">
        <div className="flex items-center space-x-2">
          {/* Replace text with logo image */}
          <img src="%PUBLIC_URL%/logo.png" alt="Shipus.net Logo" className="h-10" />
        </div>
        <nav className="hidden md:flex space-x-6 text-lg">
          <a href="#" className="hover:text-primary-accent transition-colors">Trang chủ</a>
          <a href="#pricing" className="hover:text-primary-accent transition-colors">Bảng giá</a>
          <a href="#guide" className="hover:text-primary-accent transition-colors">Hướng dẫn</a>
          <a href="#tracking" className="hover:text-primary-accent transition-colors">Tra cứu</a>
        </nav>
        <button className="bg-primary-accent hover:bg-yellow-600 text-white font-bold py-2 px-4 rounded-full flex items-center space-x-2 transition-colors">
          <Phone size={20} />
          <span>Liên hệ ngay</span>
        </button>
      </div>
    </header>
  );
}

export default Header;
